import{_ as e,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"181. Staff Appraisal","description":"","frontmatter":{"title":"181. Staff Appraisal","eba":"Mental Health Services 2024-2028","topics":["union-matters"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/181-staff-appraisal.md","filePath":"ebas/mental-health/support-services/preliminary/181-staff-appraisal.md"}'),o={name:"ebas/mental-health/support-services/preliminary/181-staff-appraisal.md"};function p(i,a,n,l,f,c){return t(),s("div",null,[...a[0]||(a[0]=[r('<h1 id="_181-staff-appraisal" tabindex="-1">181. Staff Appraisal <a class="header-anchor" href="#_181-staff-appraisal" aria-label="Permalink to &quot;181. Staff Appraisal&quot;">​</a></h1><p><strong>181.1</strong> Where a system of staff appraisal does not currently exist at a workplace, the Employer may implement a performance appraisal process and the Employees will participate in that process, provided that:</p><p><strong>(a)</strong> the Employer first consults at the local level with staff and/or their union or other representative over a framework for the staff appraisal process it is seeking to introduce</p><p><strong>(b)</strong> the staff appraisal process is not used as a disciplinary tool</p><p><strong>(c)</strong> the staff appraisal process is intended to allow genuine feedback by both the Employer and Employee; and</p><p><strong>(d)</strong> the outcomes of the review are documented and confirmed and a written copy of the outcomes in given to the Employee</p>',6)])])}const m=e(o,[["render",p]]);export{h as __pageData,m as default};
